var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하하하! 뒤통수 맞은 기분이 어떠냐, 허접들아-!","JPN":"キャハハッ！　騙された気分はどうだ、ヘタクソどもー！","ENG":"Kya hah hah hah! I got you good, ya scurvy dogs!","TWN":"哇哈哈哈！笨蛋！被人擺一道的感覺怎麼樣啊？"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"선장님! 구하러 올 거라 믿었어요!","JPN":"船長！　助けに来てくださると信じていました！","ENG":"Captain! I knew you'd come save us!","TWN":"船長！我就知道你會來救我們！"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_WATCH","text":{"KOREA":"크윽… 너희들, 이런 식으로 탈옥하고도 뒷감당을 할 수 있을 것 같아?","JPN":"くうっ……お前ら、こんな風に脱獄して大丈夫と思うのか？","ENG":"Kgh... You think you can handle the aftermath of breaking out?","TWN":"咳呃…你們用這種方式逃獄有辦法承擔後果嗎？"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_WATCH","text":{"KOREA":"프론트베이에선 어디로 도망쳐도 결국 관리국 손바닥 안이라고.","JPN":"フロントベイではどこへ逃げても結局は管理局の掌の中だ。","ENG":"You're in the hands of the Administration wherever you go in Front Bay.","TWN":"在前灣，無論你們逃到哪裡，都逃不過管理局的五指山的。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그런 말하면 누가 겁먹어? 그 관리국에서 믿고 맡긴 너희가 이런 허접인데?","JPN":"そんな言葉で誰が怖気づくと思うんだ？　その管理局が信じて任せたお前らが、こんなヘタクソなのに？","ENG":"Who'd get scared by that? The Administration put you losers in charge in the first place!","TWN":"聽到這種話有人會怕嗎？你們不是被管理局請的嗎？也不怎麼樣啊。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"풉- 풉- 선장님의 지략에 단체로 끔뻑 넘어가는 꼴이라니, 관리국의 수치네요!","JPN":"ぷーぷー船長の知略に全員騙されるなんて、管理局の恥ですね！","ENG":"Pfft! Pfft! They all fell for your trick, Captain! The Administration must be humiliated!","TWN":"噗噗，船長一句話就讓你們都啞口無言，簡直是管理局之恥！"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_WATCH","text":{"KOREA":"크윽…! 저것들이!","JPN":"くっ……！　あいつら！","ENG":"Kgh...! Why those little...!","TWN":"可惡…！你們這些傢伙！"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"선장- 도발은 그쯤 하고 얼른 도망치는 게 낫지 않아?","JPN":"船長ー挑発はそのくらいにして早く逃げた方がいいんじゃない？","ENG":"Captain. Shouldn't we stop provoking them and run?","TWN":"船長，別再跟他們廢話了，我們還是快逃吧？"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"잠깐만. 저기 잔뜩 화나서 몰려오는 바보들만 좀 찍고.","JPN":"ちょっと待って。あそこの怒りまくって走ってくるバカどもを撮ってから。","ENG":"Wait. I just gotta take a pic of those angry idiots running after us.","TWN":"等等，我先拍一下那些火冒三丈衝過來的笨蛋。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GUARD_FRONTBAY_COAST_SEVERAL","text":{"KOREA":"아직 저기 있다!","JPN":"あそこ、まだいる！","ENG":"They're still over there!","TWN":"人還在那裡！"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GUARD_FRONTBAY_COAST_SEVERAL","text":{"KOREA":"잡아라! 놓치지 마!","JPN":"捕まえろ！　逃すな！","ENG":"Get them! Don't let them get away!","TWN":"抓住她們！別讓人給跑了！"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"흐아~ 이제 안 쫓아오네요. 아슬아슬했어요.","JPN":"ひゅう～もう追いかけてきませんね。ギリギリでした。","ENG":"Phew! They're not on our tail anymore. That was close.","TWN":"呼～好像沒有再繼續追了，好險。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"푸하핫- 여기 왼쪽 녀석 좀 봐. 완전 웃긴 표정으로 찍혔네.","JPN":"キャハハッーここ、左のやつ見ろよ。ちょう変な顔になっている。","ENG":"Bah hah hah! Look at the one on the left here. That face is hilarious.","TWN":"噗哈哈，你看左邊的人，表情超好笑的。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"이번엔 너무 일을 키운 거 아냐, 선장?","JPN":"ちょっと今回はことを大きくし過ぎたんじゃないか、船長？","ENG":"Don't you think this was a bit overkill, Captain?","TWN":"船長，這次是不是有點過火？"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"적당히 보석금 내고 풀려날 줄 알았는데 말이지.","JPN":"適当に金払って解放されるのかと思ったのに。","ENG":"I thought we'd get out on bail.","TWN":"我還以為只要繳個保釋金，他們就會釋放我們了吧？"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"너무하네. 그렇게 세금 내듯이 달라는 대로 보석금을 내면 재미없잖아.","JPN":"ええ。素直に金を払ったらつまらないじゃん。","ENG":"C'mon. It's no fun to just pay bail like paying taxes.","TWN":"那怎麼行，如果他們跟你要保釋金你就繳，就像繳稅一樣，那有什麼好玩的？"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"맞아요, 소냐! 정당하게 돈을 내는 건 낭만이 아니에요! 해적답지 못하다고요!","JPN":"そうですよ、ソーニャ！　正当にお金を払うのはロマンではありません！　海賊らしくありません！","ENG":"Yeah, Sonya! It's not the pirate dream to pay money fair and square! It's un-pirate-like!","TWN":"對啊，索妮雅！乖乖繳錢一點都不浪漫！也不符合海盜的作風！"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐, 애초에 그럴 만한 돈도 없었지만.","JPN":"まぁそもそも、そんな金もないしね。","ENG":"Well, not that I had the cash to bail you out anyway.","TWN":"更何況我們又沒有錢。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};